echo "Removing /Applications/MacDown 3000.app..."
if [ -d "/Applications/MacDown 3000.app" ]; then
    rm -rf "/Applications/MacDown 3000.app" 2>/dev/null || true
elif [ -f "/Applications/MacDown 3000.app" ]; then
    rm -f "/Applications/MacDown 3000.app" 2>/dev/null || true
fi

# Remove binary /Applications/MacDown 3000.app/MacDown 3000.app/Contents/SharedSupport/bin/macdown
